304→private final class InMemoryProfileRepository: UserProfileRepository, @unchecked Sendable {
305→    private var profile: UserProfile?
306→    func loadProfile() async throws -> UserProfile? { profile }
307→    func saveProfile(_ profile: UserProfile) async throws { self.profile = profile }
308→}
309→
310→private final class InMemoryEntitlementRepository: EntitlementRepository, @unchecked Sendable {
311→    func currentEntitlement() async throws -> ProEntitlement { .free }
312→    func entitlementStream() -> AsyncStream<ProEntitlement> {
313→        AsyncStream { continuation in continuation.finish() }
314→    }
315→}
316→
317→private final class InMemoryHistoryRepository: WorkoutHistoryRepository {
318→    private var entries: [WorkoutHistoryEntry] = []
319→
320→    func listEntries() async throws -> [WorkoutHistoryEntry] {
321→        entries.sorted { $0.date > $1.date }
322→    }
323→    
324→    func listEntries(limit: Int, offset: Int) async throws -> [WorkoutHistoryEntry] {
325→        let sorted = entries.sorted { $0.date > $1.date }
326→        let start = min(offset, sorted.count)
327→        let end = min(offset + limit, sorted.count)
328→        return Array(sorted[start..<end])
329→    }
330→    
331→    func count() async throws -> Int {
332→        entries.count
333→    }
334→
335→    func saveEntry(_ entry: WorkoutHistoryEntry) async throws {
336→        entries.append(entry)
337→    }
338→
339→    func listAppEntriesWithPlan(limit: Int) async throws -> [WorkoutHistoryEntry] {
340→        let filtered = entries
341→            .filter { $0.source == .app && $0.workoutPlan != nil }
342→            .sorted { $0.date > $1.date }
343→        return Array(filtered.prefix(limit))
344→    }
345→}
