210→
211→    private var loadingView: some View {
212→        VStack(spacing: FitTodaySpacing.sm) {
213→            ForEach(0..<4, id: \.self) { _ in
214→                RoundedRectangle(cornerRadius: FitTodayRadius.md)
215→                    .fill(FitTodayColor.surface)
216→                    .frame(height: 80)
217→                    .shimmer()
218→            }
219→        }
220→    }
221→
222→    private var emptyStateView: some View {
223→        VStack(spacing: FitTodaySpacing.md) {
224→            Image(systemName: "figure.run.circle")
225→                .font(.system(size: 48))
226→                .foregroundStyle(FitTodayColor.textTertiary)
227→
228→            Text("Nenhum treino ainda")
229→                .font(FitTodayFont.ui(size: 17, weight: .semiBold))
230→                .foregroundStyle(FitTodayColor.textPrimary)
231→
232→            Text("Complete seu primeiro treino para ver seu histórico")
233→                .font(FitTodayFont.ui(size: 14, weight: .medium))
234→                .foregroundStyle(FitTodayColor.textSecondary)
235→                .multilineTextAlignment(.center)
236→        }
237→        .frame(maxWidth: .infinity)
238→        .padding(FitTodaySpacing.xl)
