240→
241→    // MARK: - Data Loading
242→
243→    private func loadWorkouts() async {
244→        guard let repository else {
245→            isLoading = false
246→            return
247→        }
248→
249→        do {
250→            let entries = try await repository.listEntries(limit: 20, offset: 0)
251→            workouts = entries
252→        } catch {
253→            workouts = []
254→        }
255→        isLoading = false
256→    }
