259→// MARK: - Month Calendar View
260→
261→struct MonthCalendarView: View {
262→    @Binding var selectedDate: Date
263→    let highlightedDays: Set<DateComponents>
264→
265→    // BUG 7 FIX: use Monday-first week to match startOfWeek used by weekly stats.
266→    private let calendar: Calendar = {
267→        var cal = Calendar.current
268→        cal.firstWeekday = 2 // Monday = 2
269→        return cal
270→    }()
271→    // Mon, Tue, Wed, Thu, Fri, Sat, Sun
272→    private let daysOfWeek = ["S", "T", "Q", "Q", "S", "S", "D"]
273→
274→    private var monthDays: [Date?] {
275→        let interval = calendar.dateInterval(of: .month, for: selectedDate)!
276→        let firstDay = interval.start
277→        // weekday in Calendar.current is 1=Sun … 7=Sat.
278→        // Convert to Monday-first column index: Mon=0 … Sun=6.
279→        let firstWeekday = Calendar.current.component(.weekday, from: firstDay)
280→        let mondayFirstOffset = (firstWeekday - 2 + 7) % 7
281→        let daysInMonth = calendar.range(of: .day, in: .month, for: selectedDate)!.count
282→
283→        var days: [Date?] = Array(repeating: nil, count: mondayFirstOffset)
284→
285→        for day in 1...daysInMonth {
286→            if let date = calendar.date(byAdding: .day, value: day - 1, to: firstDay) {
287→                days.append(date)
288→            }
289→        }
290→
291→        // Pad to complete last week
292→        while days.count % 7 != 0 {
293→            days.append(nil)
294→        }
295→
296→        return days
297→    }
298→
299→    var body: some View {
300→        VStack(spacing: FitTodaySpacing.sm) {
301→            // Month navigation
302→            HStack {
303→                Button {
304→                    withAnimation {
305→                        selectedDate = calendar.date(byAdding: .month, value: -1, to: selectedDate)!
306→                    }
307→                } label: {
308→                    Image(systemName: "chevron.left")
309→                        .foregroundStyle(FitTodayColor.textSecondary)
310→                }
311→
312→                Spacer()
313→
314→                Text(selectedDate, format: .dateTime.month(.wide).year())
315→                    .font(FitTodayFont.ui(size: 16, weight: .semiBold))
316→                    .foregroundStyle(FitTodayColor.textPrimary)
317→
318→                Spacer()
319→
320→                Button {
321→                    withAnimation {
322→                        selectedDate = calendar.date(byAdding: .month, value: 1, to: selectedDate)!
323→                    }
324→                } label: {
325→                    Image(systemName: "chevron.right")
326→                        .foregroundStyle(FitTodayColor.textSecondary)
327→                }
328→            }
329→            .padding(.horizontal, FitTodaySpacing.sm)
330→
331→            // Days of week header
332→            HStack(spacing: 0) {
333→                ForEach(daysOfWeek, id: \.self) { day in
334→                    Text(day)
335→                        .font(FitTodayFont.ui(size: 12, weight: .medium))
336→                        .foregroundStyle(FitTodayColor.textTertiary)
337→                        .frame(maxWidth: .infinity)
338→                }
339→            }
340→
341→            // Calendar grid
342→            LazyVGrid(columns: Array(repeating: GridItem(.flexible()), count: 7), spacing: FitTodaySpacing.xs) {
343→                ForEach(Array(monthDays.enumerated()), id: \.offset) { _, date in
344→                    if let date {
345→                        DayCell(
346→                            date: date,
347→                            isHighlighted: isHighlighted(date),
348→                            isSelected: calendar.isDate(date, inSameDayAs: selectedDate),
349→                            isToday: calendar.isDateInToday(date)
350→                        ) {
351→                            selectedDate = date
352→                        }
353→                    } else {
354→                        Color.clear
355→                            .frame(width: 36, height: 36)
356→                    }
357→                }
358→            }
359→        }
360→        .padding(FitTodaySpacing.md)
361→        .background(
362→            RoundedRectangle(cornerRadius: FitTodayRadius.md)
363→                .fill(FitTodayColor.surface)
364→        )
365→    }
366→
367→    private func isHighlighted(_ date: Date) -> Bool {
368→        let components = calendar.dateComponents([.year, .month, .day], from: date)
369→        return highlightedDays.contains(components)
370→    }
371→}
