//
//  FeatureFlag.swift
//  FitToday
//
//  Feature flags for remote configuration of features.
//  Used to control feature rollout and A/B testing.
//

import Foundation

// MARK: - Feature Flag Key

/// Keys for remote feature flags controlled via Firebase Remote Config.
/// Each key corresponds to a boolean flag that can be toggled remotely.
enum FeatureFlagKey: String, CaseIterable, Sendable {

    // MARK: - AI Features

    /// Enables AI-powered workout generation (OpenAI).
    case aiWorkoutGenerationEnabled = "ai_workout_generation_enabled"

    /// Enables AI exercise substitution during active workout.
    case aiExerciseSubstitutionEnabled = "ai_exercise_substitution_enabled"

    // MARK: - Social Features

    /// Enables group creation, joining, and management.
    case socialGroupsEnabled = "social_groups_enabled"

    /// Enables workout challenges within groups.
    case challengesEnabled = "challenges_enabled"

    /// Enables leaderboard ranking in groups.
    case leaderboardEnabled = "leaderboard_enabled"

    /// Enables photo check-in for challenge validation.
    case checkInEnabled = "check_in_enabled"

    /// Enables group streak tracking and display.
    case groupStreaksEnabled = "group_streaks_enabled"

    /// Enables social feed with workout proof posts.
    case socialFeedEnabled = "social_feed_enabled"

    // MARK: - Health & Sync

    /// Enables Apple Health read/write integration.
    case healthKitSyncEnabled = "healthkit_sync_enabled"

    /// Enables activity stats with Swift Charts.
    case statsChartsEnabled = "stats_charts_enabled"

    // MARK: - Content

    /// Enables structured training programs.
    case programsEnabled = "programs_enabled"

    /// Enables user-created workout templates.
    case customWorkoutsEnabled = "custom_workouts_enabled"

    /// Enables exercise library/explorer.
    case exerciseLibraryEnabled = "exercise_library_enabled"

    // MARK: - Personal Trainer

    /// Enables personal trainer integration features.
    /// When enabled, users can connect with personal trainers via CMS.
    case personalTrainerEnabled = "personal_trainer_enabled"

    /// Enables synchronization of workouts from CMS.
    /// When enabled, trainer-assigned workouts sync to the user's app.
    case cmsWorkoutSyncEnabled = "cms_workout_sync_enabled"

    /// Enables chat functionality with personal trainers.
    /// When enabled, users can message their assigned trainer.
    case trainerChatEnabled = "trainer_chat_enabled"

    // MARK: - Monetization & UX

    /// Enables paywall/Pro upgrade prompts.
    case paywallEnabled = "paywall_enabled"

    /// Enables App Store review request after workout completion.
    case reviewRequestEnabled = "review_request_enabled"

    // MARK: - Operational

    /// Shows maintenance banner and disables write operations.
    case maintenanceModeEnabled = "maintenance_mode_enabled"

    /// Shows non-dismissable update dialog directing to App Store.
    case forceUpdateEnabled = "force_update_enabled"

    // MARK: - Display Name

    /// Human-readable display name for the feature flag.
    var displayName: String {
        switch self {
        // AI
        case .aiWorkoutGenerationEnabled: return "AI Workout Generation"
        case .aiExerciseSubstitutionEnabled: return "AI Exercise Substitution"
        // Social
        case .socialGroupsEnabled: return "Social Groups"
        case .challengesEnabled: return "Challenges"
        case .leaderboardEnabled: return "Leaderboard"
        case .checkInEnabled: return "Check-In"
        case .groupStreaksEnabled: return "Group Streaks"
        case .socialFeedEnabled: return "Social Feed"
        // Health
        case .healthKitSyncEnabled: return "Apple Health Sync"
        case .statsChartsEnabled: return "Stats Charts"
        // Content
        case .programsEnabled: return "Training Programs"
        case .customWorkoutsEnabled: return "Custom Workouts"
        case .exerciseLibraryEnabled: return "Exercise Library"
        // Personal Trainer
        case .personalTrainerEnabled: return "Personal Trainer Integration"
        case .cmsWorkoutSyncEnabled: return "CMS Workout Sync"
        case .trainerChatEnabled: return "Trainer Chat"
        // Monetization
        case .paywallEnabled: return "Paywall"
        case .reviewRequestEnabled: return "Review Request"
        // Operational
        case .maintenanceModeEnabled: return "Maintenance Mode"
        case .forceUpdateEnabled: return "Force Update"
        }
    }

    // MARK: - Default Value

    /// Default value when remote config is unavailable.
    /// Existing features default to `true` (no regression).
    /// Unreleased features default to `false`.
    var defaultValue: Bool {
        switch self {
        // Unreleased features — disabled by default
        case .socialFeedEnabled,
             .personalTrainerEnabled,
             .cmsWorkoutSyncEnabled,
             .trainerChatEnabled,
             .maintenanceModeEnabled,
             .forceUpdateEnabled:
            return false

        // All existing features — enabled by default
        default:
            return true
        }
    }
}

//
//  RemoteConfigService.swift
//  FitToday
//
//  Service that wraps Firebase Remote Config for feature flag management.
//  Uses actor isolation for thread-safe access to remote config values.
//

import Foundation
import FirebaseRemoteConfig

// MARK: - Remote Config Service Protocol

/// Protocol for remote configuration service.
protocol RemoteConfigServicing: Sendable {
    /// Fetches and activates remote config values from Firebase.
    /// - Throws: Error if fetch or activation fails.
    func fetchAndActivate() async throws

    /// Gets the boolean value for a feature flag key.
    /// - Parameter key: The feature flag key to retrieve.
    /// - Returns: The boolean value for the key, or the default value if not set.
    func getValue(for key: FeatureFlagKey) async -> Bool

    /// Sets the minimum fetch interval for remote config.
    /// - Parameter interval: The minimum interval between fetches.
    func setMinimumFetchInterval(_ interval: TimeInterval) async
}

// MARK: - Remote Config Service

/// Actor that wraps Firebase Remote Config for thread-safe feature flag access.
/// Manages fetching, caching, and retrieving remote configuration values.
actor RemoteConfigService: RemoteConfigServicing {
    // MARK: - Properties

    private let remoteConfig: RemoteConfig
    private var lastFetchTime: Date?
    private var isConfigured = false

    /// Default fetch interval: 12 hours for production.
    static let defaultFetchInterval: TimeInterval = 12 * 60 * 60

    /// Debug fetch interval: 0 seconds for immediate updates.
    static let debugFetchInterval: TimeInterval = 0

    // MARK: - Initialization

    init(remoteConfig: RemoteConfig = RemoteConfig.remoteConfig()) {
        self.remoteConfig = remoteConfig
        configureDefaults()
    }

    // MARK: - Configuration

    /// Configures default values for all feature flags.
    private func configureDefaults() {
        guard !isConfigured else { return }

        // Build default values dictionary
        var defaults: [String: NSObject] = [:]
        for key in FeatureFlagKey.allCases {
            defaults[key.rawValue] = NSNumber(value: key.defaultValue)
        }

        remoteConfig.setDefaults(defaults)

        // Configure settings
        let settings = RemoteConfigSettings()
        #if DEBUG
        settings.minimumFetchInterval = Self.debugFetchInterval
        #else
        settings.minimumFetchInterval = Self.defaultFetchInterval
        #endif

        remoteConfig.configSettings = settings
        isConfigured = true
    }

    // MARK: - Public Methods

    func fetchAndActivate() async throws {
        do {
            let status = try await remoteConfig.fetchAndActivate()

            switch status {
            case .successFetchedFromRemote:
                lastFetchTime = Date()
                #if DEBUG
                print("[RemoteConfig] Successfully fetched from remote")
                #endif

            case .successUsingPreFetchedData:
                #if DEBUG
                print("[RemoteConfig] Using pre-fetched data")
                #endif

            case .error:
                #if DEBUG
                print("[RemoteConfig] Fetch returned error status")
                #endif

            @unknown default:
                #if DEBUG
                print("[RemoteConfig] Unknown fetch status")
                #endif
            }
        } catch {
            #if DEBUG
            print("[RemoteConfig] Fetch failed: \(error.localizedDescription)")
            #endif
            throw RemoteConfigError.fetchFailed(underlying: error)
        }
    }

    func getValue(for key: FeatureFlagKey) async -> Bool {
        let configValue = remoteConfig.configValue(forKey: key.rawValue)

        // If no value is set remotely, use default
        if configValue.source == .static {
            return key.defaultValue
        }

        return configValue.boolValue
    }

    func setMinimumFetchInterval(_ interval: TimeInterval) async {
        let settings = RemoteConfigSettings()
        settings.minimumFetchInterval = interval
        remoteConfig.configSettings = settings
    }

    // MARK: - Debug Helpers

    #if DEBUG
    /// Returns the source of a config value (for debugging).
    func getValueSource(for key: FeatureFlagKey) async -> RemoteConfigSource {
        remoteConfig.configValue(forKey: key.rawValue).source
    }

    /// Returns all current config values (for debugging).
    func getAllValues() async -> [String: Bool] {
        var values: [String: Bool] = [:]
        for key in FeatureFlagKey.allCases {
            values[key.rawValue] = await getValue(for: key)
        }
        return values
    }
    #endif
}

// MARK: - Remote Config Error

/// Errors that can occur during remote config operations.
enum RemoteConfigError: LocalizedError {
    case fetchFailed(underlying: Error)
    case activationFailed(underlying: Error)
    case notConfigured

    var errorDescription: String? {
        switch self {
        case .fetchFailed(let error):
            return "Failed to fetch remote config: \(error.localizedDescription)"
        case .activationFailed(let error):
            return "Failed to activate remote config: \(error.localizedDescription)"
        case .notConfigured:
            return "Remote config service is not configured"
        }
    }
}

//
//  RemoteConfigFeatureFlagRepository.swift
//  FitToday
//
//  Implementation of FeatureFlagRepository using Firebase Remote Config.
//  Includes UserDefaults caching for offline support.
//

import Foundation

// MARK: - Remote Config Feature Flag Repository

/// Implementation of FeatureFlagRepository that uses Firebase Remote Config
/// with UserDefaults caching for offline access.
final class RemoteConfigFeatureFlagRepository: FeatureFlagRepository, @unchecked Sendable {
    // MARK: - Properties

    private let remoteConfigService: RemoteConfigServicing
    private let userDefaults: UserDefaults
    private let cacheKeyPrefix = "feature_flag_cache_"

    // MARK: - Initialization

    /// Creates a new feature flag repository.
    /// - Parameters:
    ///   - remoteConfigService: The remote config service to use for fetching values.
    ///   - userDefaults: UserDefaults instance for caching (defaults to standard).
    init(
        remoteConfigService: RemoteConfigServicing,
        userDefaults: UserDefaults = .standard
    ) {
        self.remoteConfigService = remoteConfigService
        self.userDefaults = userDefaults
    }

    // MARK: - FeatureFlagRepository

    func isEnabled(_ key: FeatureFlagKey) async -> Bool {
        // Get value from remote config service
        let remoteValue = await remoteConfigService.getValue(for: key)

        // Cache the value for offline access
        cacheValue(remoteValue, for: key)

        return remoteValue
    }

    func fetchAndActivate() async throws {
        try await remoteConfigService.fetchAndActivate()

        // After successful fetch, update cache for all keys
        for key in FeatureFlagKey.allCases {
            let value = await remoteConfigService.getValue(for: key)
            cacheValue(value, for: key)
        }
    }

    // MARK: - Caching

    /// Caches a feature flag value to UserDefaults.
    /// - Parameters:
    ///   - value: The boolean value to cache.
    ///   - key: The feature flag key.
    private func cacheValue(_ value: Bool, for key: FeatureFlagKey) {
        let cacheKey = cacheKeyPrefix + key.rawValue
        userDefaults.set(value, forKey: cacheKey)
    }

    /// Retrieves a cached feature flag value from UserDefaults.
    /// - Parameter key: The feature flag key.
    /// - Returns: The cached value, or the default value if not cached.
    func getCachedValue(for key: FeatureFlagKey) -> Bool {
        let cacheKey = cacheKeyPrefix + key.rawValue

        // Check if value exists in cache
        if userDefaults.object(forKey: cacheKey) != nil {
            return userDefaults.bool(forKey: cacheKey)
        }

        // Return default value if not cached
        return key.defaultValue
    }

    /// Clears all cached feature flag values.
    func clearCache() {
        for key in FeatureFlagKey.allCases {
            let cacheKey = cacheKeyPrefix + key.rawValue
            userDefaults.removeObject(forKey: cacheKey)
        }
    }
}

