  7→
  8→import Foundation
  9→import FirebaseFirestore
 10→
 11→// MARK: - Firebase Feed Service
 12→
 13→actor FirebaseFeedService {
 14→    private let db = Firestore.firestore()
 15→
 16→    private var postsCollection: CollectionReference {
 17→        db.collection("feed_posts")
 18→    }
 19→
 20→    // MARK: - Posts
 21→
 22→    func createPost(_ fbPost: FBFeedPost) async throws -> FBFeedPost {
 23→        let docRef = postsCollection.document(fbPost.id ?? UUID().uuidString)
 24→        try docRef.setData(from: fbPost)
 25→        let snapshot = try await docRef.getDocument()
 26→        guard let created = try? snapshot.data(as: FBFeedPost.self) else {
 27→            throw FeedError.postNotFound
 28→        }
 29→        return created
 30→    }
 31→
 32→    func deletePost(_ postId: String) async throws {
 33→        // Delete comments subcollection first
 34→        let commentsSnap = try await postsCollection.document(postId)
 35→            .collection("comments").getDocuments()
 36→        let batch = db.batch()
 37→        for doc in commentsSnap.documents {
 38→            batch.deleteDocument(doc.reference)
 39→        }
 40→        batch.deleteDocument(postsCollection.document(postId))
 41→        try await batch.commit()
 42→    }
 43→
 44→    func getPosts(groupId: String, limit: Int, after: Date?) async throws -> [FBFeedPost] {
 45→        var query = postsCollection
 46→            .whereField("groupId", isEqualTo: groupId)
 47→            .order(by: "createdAt", descending: true)
 48→            .limit(to: limit)
 49→
 50→        if let after {
 51→            query = query.whereField("createdAt", isLessThan: Timestamp(date: after))
 52→        }
 53→
 54→        let snapshot = try await query.getDocuments()
 55→        return snapshot.documents.compactMap { try? $0.data(as: FBFeedPost.self) }
 56→    }
 57→
 58→    func observePosts(groupId: String) -> AsyncStream<[FBFeedPost]> {
 59→        AsyncStream { continuation in
 60→            let listener = postsCollection
 61→                .whereField("groupId", isEqualTo: groupId)
