 3→//  FitToday
 4→//
 5→//  Shows 7 day circles for the current week with streak count.
 6→//
 7→
 8→import SwiftUI
 9→
10→struct WeekStreakRow: View {
11→    let completedDays: Set<Int>
12→    let currentStreak: Int
13→
14→    private let dayLabels = ["S", "M", "T", "W", "T", "F", "S"]
15→    private let circleSize: CGFloat = 36
16→
17→    private var todayWeekday: Int {
18→        Calendar.current.component(.weekday, from: Date()) - 1 // 0=Sunday
19→    }
20→
21→    var body: some View {
22→        VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
23→            // Streak label
24→            HStack(spacing: FitTodaySpacing.xs) {
25→                Image(systemName: "flame.fill")
26→                    .font(.system(size: 14))
27→                    .foregroundStyle(FitTodayColor.brandPrimary)
28→                Text("\(currentStreak) day streak")
29→                    .font(FitTodayFont.ui(size: 14, weight: .semiBold))
30→                    .foregroundStyle(FitTodayColor.textPrimary)
31→            }
32→
33→            // Day circles
34→            HStack(spacing: 0) {
35→                ForEach(0..<7, id: \.self) { index in
36→                    dayCircle(for: index)
37→                        .frame(maxWidth: .infinity)
38→                }
39→            }
40→        }
41→        .padding(FitTodaySpacing.md)
42→        .background(FitTodayColor.surface)
43→        .clipShape(RoundedRectangle(cornerRadius: FitTodayRadius.md))
44→    }
45→
46→    @ViewBuilder
47→    private func dayCircle(for index: Int) -> some View {
48→        let isCompleted = completedDays.contains(index)
49→        let isToday = index == todayWeekday
50→
51→        VStack(spacing: FitTodaySpacing.xs) {
52→            ZStack {
53→                Circle()
54→                    .fill(isCompleted ? FitTodayColor.brandPrimary : FitTodayColor.surfaceElevated)
55→                    .frame(width: circleSize, height: circleSize)
56→
57→                if isToday {
58→                    Circle()
59→                        .stroke(FitTodayColor.brandSecondary, lineWidth: 2)
60→                        .frame(width: circleSize, height: circleSize)
61→                }
62→
63→                if isCompleted {
64→                    Image(systemName: "checkmark")
65→                        .font(.system(size: 14, weight: .bold))
66→                        .foregroundStyle(FitTodayColor.textPrimary)
67→                }
68→            }
69→
70→            Text(dayLabels[index])
71→                .font(FitTodayFont.ui(size: 12, weight: .medium))
72→                .foregroundStyle(isToday ? FitTodayColor.textPrimary : FitTodayColor.textSecondary)
73→        }
74→    }
75→}
