371→    private func exportToHealthKitIfPossible() async {
372→        guard status == .completed else { return }
373→        guard canUseHealthKit, healthKitState == .authorized else {
374→            healthKitExportMessage = "Conecte o Apple Health antes de exportar."
375→            return
376→        }
377→        guard let plan = sessionStore.plan else { return }
378→        guard
379→            let healthKit = resolver.resolve(HealthKitServicing.self),
380→            let historyRepo = resolver.resolve(WorkoutHistoryRepository.self)
381→        else { return }
382→        
383→        do {
384→            isExportingHealthKit = true
385→            defer { isExportingHealthKit = false }
386→            
387→            let receipt = try await healthKit.exportWorkout(plan: plan, completedAt: Date())
388→            
389→            // Vincular UUID ao último item do histórico com este planId (melhor esforço)
390→            let recent = try await historyRepo.listEntries(limit: 20, offset: 0)
391→            if let idx = recent.firstIndex(where: { $0.planId == plan.id }) {
392→                var updated = recent[idx]
393→                updated.healthKitWorkoutUUID = receipt.workoutUUID
394→                try await historyRepo.saveEntry(updated)
395→            }
396→            
397→            healthKitExportMessage = "Exportado para Apple Health."
398→        } catch {
399→            healthKitExportMessage = "Falha ao exportar para Apple Health: \(error.localizedDescription)"
400→        }
401→    }
