403→    private func generateNewWorkout() {
404→        guard let profileRepo = resolver.resolve(UserProfileRepository.self),
405→              let blocksRepo = resolver.resolve(WorkoutBlocksRepository.self),
406→              let composer = resolver.resolve(WorkoutPlanComposing.self) else {
407→            errorMessage = "Não foi possível carregar as configurações necessárias."
408→            return
409→        }
410→        
411→        isGeneratingNewPlan = true
412→        
413→        Task {
414→            do {
415→                // Busca o último checkIn usado (pode ser armazenado em UserDefaults ou no sessionStore)
416→                // Por enquanto, vamos usar o checkIn padrão baseado no perfil
417→                let profileUseCase = GetUserProfileUseCase(repository: profileRepo)
418→                guard let profile = try await profileUseCase.execute() else {
419→                    errorMessage = "Perfil não encontrado. Configure seu perfil primeiro."
420→                    isGeneratingNewPlan = false
421→                    return
422→                }
423→                
424→                // Gera um novo checkIn baseado no último foco usado (ou padrão)
425→                // Para simplificar, vamos usar o mesmo foco do plano atual
426→                let currentFocus = sessionStore.plan?.focus ?? .fullBody
427→                let checkIn = DailyCheckIn(
428→                    focus: currentFocus,
429→                    sorenessLevel: .none, // Novo treino sem considerar dor anterior
430→                    sorenessAreas: [],
431→                    energyLevel: 5
432→                )
433→                
434→                let generator = GenerateWorkoutPlanUseCase(
435→                    blocksRepository: blocksRepo,
436→                    composer: composer
437→                )
438→                let newPlan = try await generator.execute(profile: profile, checkIn: checkIn)
439→                
440→                await MainActor.run {
441→                    sessionStore.reset()
442→                    sessionStore.start(with: newPlan)
443→                    isGeneratingNewPlan = false
444→                    
445→                    // Navega para o novo treino
446→                    router.pop(on: .home) // summary
447→                    router.push(.workoutPlan(newPlan.id), on: .home)
448→                }
449→            } catch {
450→                await MainActor.run {
451→                    errorMessage = error.localizedDescription
452→                    isGeneratingNewPlan = false
453→                }
454→            }
455→        }
456→    }
