139→    var streakDays: Int {
140→        guard !historyEntries.isEmpty else { return 0 }
141→
142→        let calendar = Calendar.current
143→        let sortedDates = historyEntries
144→            .map { calendar.startOfDay(for: $0.date) }
145→            .sorted(by: >)
146→
147→        guard let mostRecent = sortedDates.first else { return 0 }
148→
149→        // Check if streak is still active (workout today or yesterday)
150→        let today = calendar.startOfDay(for: Date())
151→        let yesterday = calendar.date(byAdding: .day, value: -1, to: today)!
152→
153→        guard mostRecent >= yesterday else { return 0 }
154→
155→        var streak = 1
156→        var currentDate = mostRecent
157→
158→        for date in sortedDates.dropFirst() {
159→            let expectedPrevious = calendar.date(byAdding: .day, value: -1, to: currentDate)!
160→            if date == expectedPrevious {
161→                streak += 1
162→                currentDate = date
163→            } else if date == currentDate {
164→                // Same day, skip
165→                continue
166→            } else {
167→                break
168→            }
169→        }
170→
171→        return streak
172→    }
