    // Social feed post state
    @State private var showCreatePost = false
    @State private var showPostSuccess = false

    // XP/Level state
    @State private var xpAwardResult: XPAwardResult?
    @State private var showLevelUp = false

    // Success feedback
    @State private var didPlayHaptic = false
    @State private var showCompletionCelebration = false

    @Environment(\.accessibilityReduceMotion) private var reduceMotion
    @State private var iconScale: CGFloat = 0.3
    @State private var iconOpacity: Double = 0

    var body: some View {
        VStack(spacing: FitTodaySpacing.lg) {
            Image(systemName: statusIcon)
                .resizable()
                .scaledToFit()
                .frame(width: 96, height: 96)
                .foregroundStyle(statusColor)
                .scaleEffect(iconScale)
                .opacity(iconOpacity)

            VStack(spacing: FitTodaySpacing.sm) {
                Text(titleText)
                    .font(.system(.title2, weight: .bold))
                Text(descriptionText)
                    .font(.system(.body))
                    .foregroundStyle(FitTodayColor.textSecondary)
                    .multilineTextAlignment(.center)
            }
            .padding(.horizontal)

            // Workout summary statistics for completed workouts
            if status == .completed {
                workoutSummaryCard
            }

            // Rating prompt for completed workouts
            if status == .completed && !hasRated {
                WorkoutRatingView(
                    selectedRating: $selectedRating,
                    onRatingSelected: { rating in
                        Task { await saveRating(rating) }
                    },
                    onSkip: {
                        hasRated = true
                    }
                )
                .padding(.horizontal)
            }

            // Check-in button (only for users in a group after rating)
            if status == .completed && hasRated && isInGroup {
                Button {
                    showCheckInSheet = true
                } label: {
                    Label("Fazer Check-in com Foto", systemImage: "camera.fill")
                }
                .fitPrimaryStyle()
                .padding(.horizontal)
            }

            // Social feed post button (after rating, for users in a group)
            if status == .completed && hasRated && isInGroup {
                Button {
                    showCreatePost = true
                } label: {
                    Label("Postar no Feed", systemImage: "square.and.arrow.up")
                }
                .fitSecondaryStyle()
                .padding(.horizontal)
            }

            // Prompt para completar perfil (se incompleto)
            if isProfileIncomplete && status == .completed && hasRated {
                profileCompletionPrompt
            }

            VStack(spacing: FitTodaySpacing.sm) {
                // Se foi pulado, oferece opção de gerar novo treino
                if status == .skipped {
                    Button("Gerar Novo Treino") {
                        generateNewWorkout()
                    }
                    .fitPrimaryStyle()
                    .disabled(isGeneratingNewPlan)

