                        ProgressView()
                            .padding()
                    }
                }

                Button(primaryCTATitle) {
                    finalizeFlow(goToHistory: false)
                }
                .fitPrimaryStyle()
                .disabled(isGeneratingNewPlan)

                if status == .completed {
                    if canUseHealthKit {
                        Button(isExportingHealthKit ? "Exportando..." : "Exportar para Apple Health") {
                            Task { await exportToHealthKitIfPossible() }
                        }
                        .fitSecondaryStyle()
                        .disabled(isExportingHealthKit || healthKitState != .authorized)
                    }

                    Button("Ver histórico") {
                        finalizeFlow(goToHistory: true)
                    }
                    .fitSecondaryStyle()
                }
            }

            if let msg = healthKitExportMessage {
                Text(msg)
                    .font(.system(.footnote, weight: .medium))
                    .foregroundStyle(FitTodayColor.textSecondary)
                    .multilineTextAlignment(.center)
                    .padding(.horizontal)
            }

            Spacer()
        }
        .padding()
        .navigationTitle("Resumo")
        .navigationBarBackButtonHidden(true)
        .task {
            await checkProfileCompletion()
            await loadHealthKitAvailability()
            await checkGroupMembership()
            loadCurrentEntry()
            playSuccessHapticIfNeeded()
        }
        .sheet(isPresented: $showProfilePrompt) {
            if let resolver = resolver as? Resolver {
                OnboardingFlowView(resolver: resolver, isEditing: true) {
                    showProfilePrompt = false
                    isProfileIncomplete = false
                }
            }
        }
        .alert("Erro", isPresented: Binding(
            get: { errorMessage != nil },
            set: { _ in errorMessage = nil }
        )) {
            Button("Ok", role: .cancel) {}
        } message: {
            Text(errorMessage ?? "Ocorreu um erro ao gerar novo treino.")
        }
        .sheet(isPresented: $showCheckInSheet) {
            if let entry = currentEntry,
               let checkInUseCase = resolver.resolve(CheckInUseCase.self),
               let networkMonitor = resolver.resolve(NetworkMonitor.self) {
                CheckInPhotoView(
                    viewModel: CheckInViewModel(
                        checkInUseCase: checkInUseCase,
                        workoutEntry: entry,
                        networkMonitor: networkMonitor
                    ),
                    workoutEntry: entry,
                    onSuccess: { _ in
                        showCelebration = true
                    }
                )
            }
        }
        .sheet(isPresented: $showCreatePost) {
            if let createUseCase = resolver.resolve(CreateFeedPostUseCase.self) {
                CreatePostView(
                    viewModel: CreatePostViewModel(
                        createPostUseCase: createUseCase,
                        workoutTitle: sessionStore.plan?.title ?? "Treino",
                        workoutDurationMinutes: sessionStore.lastWorkoutElapsedSeconds / 60,
                        exerciseCount: sessionStore.completedExercisesCount,
                        totalVolume: nil
                    ),
                    onSuccess: {
                        showPostSuccess = true
                    }
                )
            }
        }
        .overlay {
            if showCompletionCelebration {
                CelebrationOverlay(type: .checkInComplete)
                    .allowsHitTesting(false)
                    .task {
                        try? await Task.sleep(for: .seconds(3))
                        showCompletionCelebration = false
                    }
            }
            if showCelebration {
                CelebrationOverlay(type: .checkInComplete)
                    .onTapGesture {
                        showCelebration = false
                    }
                    .task {
                        try? await Task.sleep(for: .seconds(3))
                        showCelebration = false
                    }
            }
            if showPostSuccess {
                CelebrationOverlay(type: .checkInComplete)
                    .onTapGesture {
                        showPostSuccess = false
                    }
                    .task {
                        try? await Task.sleep(for: .seconds(3))
                        showPostSuccess = false
                    }
            }
        }
        .onChange(of: hasRated) { _, rated in
            if rated {
                requestAppReviewIfEligible()
            }
        }
    }

