//  FitToday
//

import SwiftUI

struct LevelUpCelebrationView: View {
    let level: Int
    let levelTitle: XPLevel
    let onDismiss: () -> Void

    @Environment(\.accessibilityReduceMotion) private var reduceMotion
    @State private var showContent = false

    var body: some View {
        ZStack {
            Color.black.opacity(0.6)
                .ignoresSafeArea()
                .onTapGesture { onDismiss() }

            if !reduceMotion {
                ConfettiView()
                    .ignoresSafeArea()
                    .allowsHitTesting(false)
            }

            VStack(spacing: FitTodaySpacing.lg) {
                Image(systemName: levelTitle.icon)
                    .font(.system(size: 64))
                    .foregroundStyle(FitTodayColor.brandPrimary)

                Text("Parabéns!")
                    .font(.system(.largeTitle, weight: .bold))
                    .foregroundStyle(FitTodayColor.textPrimary)

                Text("Nível \(level)")
                    .font(.system(.title, weight: .bold))
                    .foregroundStyle(FitTodayColor.brandPrimary)

                Text(levelTitle.rawValue)
                    .font(.system(.title2, weight: .semibold))
                    .foregroundStyle(FitTodayColor.textSecondary)
            }
            .scaleEffect(showContent ? 1 : 0.5)
            .opacity(showContent ? 1 : 0)
        }
        .onAppear {
            withAnimation(reduceMotion ? .none : .spring(response: 0.5, dampingFraction: 0.6)) {
                showContent = true
            }
        }
        .task {
            try? await Task.sleep(for: .seconds(5))
            onDismiss()
        }
    }
}

// MARK: - Confetti View

struct ConfettiView: View {
    @State private var particles: [ConfettiParticle] = []
    @State private var startTime = Date()

    private let colors: [Color] = [.red, .orange, .yellow, .green, .blue, .purple, .pink]

    var body: some View {
        TimelineView(.animation) { timeline in
            Canvas { context, size in
                let elapsed = timeline.date.timeIntervalSince(startTime)
                for particle in particles {
                    let age = elapsed - particle.delay
                    guard age > 0 else { continue }

                    let x = particle.startX * size.width + sin(age * particle.wobble) * 30
                    let y = age * particle.speed * size.height / 4
                    let opacity = max(0, 1 - age / 4)

                    guard y < size.height, opacity > 0 else { continue }

                    var path = Path()
                    path.addRect(CGRect(x: x - 4, y: y - 4, width: 8, height: 8))
                    context.fill(path, with: .color(particle.color.opacity(opacity)))
                }
            }
        }
        .onAppear {
            particles = (0..<60).map { _ in
                ConfettiParticle(
                    startX: Double.random(in: 0...1),
                    speed: Double.random(in: 0.5...1.5),
                    delay: Double.random(in: 0...0.5),
                    wobble: Double.random(in: 2...6),
                    color: colors.randomElement() ?? .yellow
                )
            }
        }
    }
}

private struct ConfettiParticle {
    let startX: Double
    let speed: Double
    let delay: Double
    let wobble: Double
    let color: Color
}

